module counter_4bit(obf_clk, rst, count);  

    input  obf_clk;  
    input rst;  
    output  [3:0] count;  
    reg   [3:0]  count; 

    always @(posedge obf_clk or posedge rst)
          begin
            if (rst)
                count <= 0;
            else
                count <= count + 1;
          end  

endmodule
